                              </div>
                          </div>
                      </div>
                  </div>
              </div>
          )}
      </div>

      {/* Confirmation Modal Portal */}
      {confirmModal.isOpen && createPortal(
           <div className="fixed inset-0 z-[1000] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))}>
               <div className="bg-[#1a1f2e] border-2 border-red-600 rounded-3xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                   <div className="text-center mb-8">
                       <h3 className="text-xl font-black text-white mb-2 uppercase tracking-tighter">{confirmModal.title}</h3>
                       <div className="text-slate-400 text-sm font-medium leading-relaxed">{confirmModal.message}</div>
                   </div>
                   <div className="flex gap-3">
                       <button onClick={() => setConfirmModal(prev => ({ ...prev, isOpen: false }))} className="flex-1 py-4 bg-slate-800 text-slate-300 rounded-2xl font-black uppercase text-[10px] tracking-widest">{t('btn_cancel')}</button>
                       <button onClick={() => { confirmModal.onConfirm(); setConfirmModal(prev => ({ ...prev, isOpen: false })); }} className="flex-1 py-4 bg-red-600 text-white rounded-2xl font-black shadow-lg uppercase text-[10px] tracking-widest">POTVRDIŤ</button>
                   </div>
               </div>
           </div>,
           document.body
       )}
    </div>
  );
};

